def _truthy_env(name: str) -> bool:
    return os.environ.get(name, '0').lower() not in {'', '0', 'false', 'no'}

def _forced_fallback(inputs: dict[str, Any]) -> bool:
    return bool(inputs.get('force_fallback', False)) or _truthy_env('LOOM_KNN_Q768_M98304_FORCE_FALLBACK') or _truthy_env('LOOM_KNN_GENERALIZE_FORCE_FALLBACK')

def _use_q768_m98304_k10(inputs: dict[str, Any]) -> bool:
    return int(inputs['B']) == 1 and int(inputs['Q']) == 768 and (int(inputs['M']) == 98304) and (int(inputs['D']) == D_STATIC) and (int(inputs['K']) == K_MAX) and (not bool(inputs.get('self_search', False))) and mma._tcgen05_capable_arch()

def selected_route(inputs: dict[str, Any]) -> str:
    if _forced_fallback(inputs):
        return parent.selected_route(inputs)
    if _use_q768_m98304_k10(inputs):
        return ROUTE_Q768_M98304_K10
    return parent.selected_route(inputs)

def selected_route_name(inputs: dict[str, Any]) -> str:
    return selected_route(inputs)

def route_info(inputs: dict[str, Any]) -> dict[str, Any]:
    route = selected_route(inputs)
    specialized = route == ROUTE_Q768_M98304_K10
    return {'route': route, 'parent_route': None if specialized else parent.selected_route(inputs), 'route_kind': 'specialized' if specialized else 'fallback', 'route_source': 'shape-specific-seed' if specialized else 'inherited-f39e-dispatcher', 'coverage_class': 'performance_route' if specialized else 'inherited_weave_route', 'coverage_only': False, 'production_policy': 'weave_only', 'external_fallback': None, 'guard_order': [entry['shape_key'] for entry in SHAPE_DISPATCH_REGISTRY], 'forced_fallback': _forced_fallback(inputs), 'selected_guard': SHAPE_DISPATCH_REGISTRY[0]['guard'] if specialized else 'q768 exact guard miss', 'fallback': None if specialized else ROUTE_PARENT_F39E}

def route_trace_entry(label: str, inputs: dict[str, Any]) -> dict[str, Any]:
    return {'label': label, 'B': int(inputs['B']), 'Q': int(inputs['Q']), 'M': int(inputs['M']), 'D': int(inputs['D']), 'K': int(inputs['K']), **route_info(inputs)}

def _launch_q768_m98304_k10(inputs: dict[str, Any]) -> dict[str, Any]:
    import torch
    if not mma._KNN_SEARCH_KERNELS:
        mma._KNN_SEARCH_KERNELS.update(mma._compile_kernels())
    bsz = int(inputs['B'])
    q_rows = int(inputs['Q'])
    m_rows = int(inputs['M'])
    k = int(inputs['K'])
    split_m = Q768_TARGET_SPLIT_M
    num_q_tiles = math.ceil(q_rows / BLOCK_Q)
    total_m_tiles = math.ceil(m_rows / BLOCK_M)
    tiles_per_split = math.ceil(total_m_tiles / split_m)
    partial_dist, partial_idx = mma._scratch(inputs, split_m, num_q_tiles)
    mma._KNN_SEARCH_KERNELS['partial_full'].launch(grid=(bsz * num_q_tiles * split_m, 1, 1), block=(THREADS, 1, 1), args=[inputs['queries'], inputs['database'], partial_dist, partial_idx, bsz, q_rows, m_rows, split_m, num_q_tiles, total_m_tiles, tiles_per_split], shared_mem=mma.MMA_SMEM_BYTES)
    mma._KNN_SEARCH_KERNELS['merge_stream'].launch(grid=(bsz * q_rows, 1, 1), block=(MERGE_THREADS, 1, 1), args=[partial_dist, partial_idx, inputs['out_distances'], inputs['out_indices'], bsz, q_rows, k, split_m, num_q_tiles], shared_mem=mma.MERGE_SMEM_BYTES)
    return {'distances': inputs['out_distances'], 'indices': inputs['out_indices']}

def launch_for_eval(inputs: dict[str, Any]) -> dict[str, Any]:
    if selected_route(inputs) == ROUTE_Q768_M98304_K10:
        return _launch_q768_m98304_k10(inputs)
    return parent.launch_for_eval(inputs)

def _select_contract_shapes(shape_labels: str | tuple[str, ...] | list[str] | None):
    if shape_labels is None:
        return [Q768_M98304_K10_SHAPE]
    from .._dispatch_runtime import select_named_shapes
    labels = [shape_labels] if isinstance(shape_labels, str) else list(shape_labels)
    if labels == [Q768_M98304_K10_SHAPE['label']]:
        return [Q768_M98304_K10_SHAPE]
    return select_named_shapes(labels)

def knn_search_compile_and_launch_q768_m98304_k10(*, benchmark: bool=True, shapes: list[dict[str, Any]] | None=None) -> dict[str, Any]:
    from .._dispatch_runtime import evaluate
    result = evaluate(launch_for_eval, shapes=[Q768_M98304_K10_SHAPE] if shapes is None else shapes, benchmark=benchmark)
    result['passed'] = bool(result.get('summary', {}).get('all_correct'))
    print(result)
    return result
